-- {"operators": "INNER_JOIN,AGGREGATE", "complexity": "high", "is_incremental": true, "has_nulls": false, "has_cast": false, "has_case": false, "tables": "WAREHOUSE,DISTRICT,CUSTOMER,OORDER,ORDER_LINE,ITEM,STOCK"}
SELECT w.W_ID, d.D_ID, i.I_ID, i.I_NAME, i.I_PRICE, s.S_QUANTITY, SUM(ol.OL_QUANTITY) AS qty_ordered, SUM(ol.OL_AMOUNT) AS revenue, COUNT(*) AS line_count FROM WAREHOUSE w JOIN DISTRICT d ON w.W_ID = d.D_W_ID JOIN OORDER o ON d.D_W_ID = o.O_W_ID AND d.D_ID = o.O_D_ID JOIN CUSTOMER c ON o.O_W_ID = c.C_W_ID AND o.O_D_ID = c.C_D_ID AND o.O_C_ID = c.C_ID JOIN ORDER_LINE ol ON o.O_W_ID = ol.OL_W_ID AND o.O_D_ID = ol.OL_D_ID AND o.O_ID = ol.OL_O_ID JOIN ITEM i ON ol.OL_I_ID = i.I_ID JOIN STOCK s ON ol.OL_W_ID = s.S_W_ID AND ol.OL_I_ID = s.S_I_ID GROUP BY w.W_ID, d.D_ID, i.I_ID, i.I_NAME, i.I_PRICE, s.S_QUANTITY;
